function uid() { return globalThis.crypto?.randomUUID?.() || `id-${Date.now()}-${Math.random().toString(36).slice(2)}`; }
function today() { return new Date().toISOString().slice(0, 10); }
function dateFromToday(days) { const date = new Date(); date.setDate(date.getDate() + days); return date.toISOString().slice(0, 10); }
function deepClone(value) { return JSON.parse(JSON.stringify(value)); }
function safeFileName(name) { return name.normalize("NFKD").replace(/[^a-zA-Z0-9._-]+/g, "-").replace(/^-+|-+$/g, "").slice(0, 140) || "evidence"; }
function normalizeHeader(value) { return String(value || "").toLowerCase().trim().replace(/[^a-z0-9]+/g, ""); }
function createRecordId() { return `NCA-${today().replaceAll("-", "")}-${Math.random().toString(36).slice(2, 6).toUpperCase()}`; }
function money(value) { return Number(value || 0).toLocaleString(undefined, { style: "currency", currency: "USD", maximumFractionDigits: 0 }); }
function daysUntil(date) { return date ? Math.ceil((new Date(date).getTime() - new Date(today()).getTime()) / 86400000) : null; }

function parseDelimited(text) {
  const rows = []; const delimiter = text.includes("\t") ? "\t" : ","; let row = [], cell = "", quoted = false;
  for (let index = 0; index < text.length; index += 1) {
    const character = text[index];
    if (character === '"') { if (quoted && text[index + 1] === '"') { cell += '"'; index += 1; } else quoted = !quoted; }
    else if (character === delimiter && !quoted) { row.push(cell.trim()); cell = ""; }
    else if ((character === "\n" || character === "\r") && !quoted) { if (character === "\r" && text[index + 1] === "\n") index += 1; row.push(cell.trim()); if (row.some((value) => value !== "")) rows.push(row); row = []; cell = ""; }
    else cell += character;
  }
  row.push(cell.trim()); if (row.some((value) => value !== "")) rows.push(row); return rows;
}

