  const [setup, setSetup] = useState({ organization: "QMSPilot Design Partner", site: "", assuranceOwner: "", responseStandard: "24-hour acknowledgment / 48-hour containment", leadershipIntent: "Protect customer trust, revenue, and recovery commitments through controlled response and verified corrective action." });
