    const critical = activeComplaints.filter((item) => item.severity === "critical").length;
    const overdue = activeComplaints.filter((item) => [item.acknowledgmentDue, item.containmentDue, item.finalResponseDue].some((date) => date && daysUntil(date) < 0)).length;
    const revenueRisk = activeComplaints.reduce((sum, item) => sum + Number(item.revenueExposure || 0), 0);
    const warrantyCost = rmas.reduce((sum, item) => sum + Number(item.repairCost || 0) + Number(item.replacementCost || 0) + Number(item.freightCost || 0) + Number(item.sortingCost || 0) + Number(item.fieldServiceCost || 0) + Number(item.chargeback || 0) + Number(item.creditIssued || 0) - Number(item.supplierRecovery || 0), 0);
