  function archiveCustomer(customer) { setCustomers((current) => current.map((item) => item.id === customer.id ? { ...item, archived: true, status: "inactive", history: addHistory(item.history, "Customer archived", "Removed from active account management.") } : item)); setSubmitted(false); }
